where nickname = #{loginName}
   or email = #{loginName}
limit 1

mapper.insert:
insert into `user`(
    password, nickname, avatar, gender, email, signature, status, remark
) values (
    #{password}, #{nickname}, #{avatar}, #{gender}, #{email}, #{signature}, #{status}, #{remark}
)

mapper.update:
update `user`
set last_login_time = now()
where id = #{id}

mapper.select:
select 
from `user` u
where 1 = 1

    and (
        u.nickname like concat('%', #{keyword}, '%')
        or u.email like concat('%', #{keyword}, '%')
    )


    and u.gender = #{gender}


    and u.status = #{status}

order by u.update_time desc, u.id desc
limit #{offset}, #{limit}

select count(1)
from `user` u
where 1 = 1

    and (
        u.nickname like concat('%', #{keyword}, '%')
        or u.email like concat('%', #{keyword}, '%')
    )


    and u.gender = #{gender}


    and u.status = #{status}

